import React, { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useData } from '../../context/DataContext';

const FacilityCheck = () => {
  const { user } = useAuth();
  const { addFacilityLog } = useData();
  
  // State quản lý thời điểm và khu vực
  const [checkType, setCheckType] = useState('Đầu giờ'); 
  const [selectedArea, setSelectedArea] = useState(''); // State lưu khu vực được chọn

  // Danh sách các hạng mục cần kiểm tra (đã thêm Cây cối)
  const items = [
    'Máy lạnh', 
    'Đèn chiếu sáng', 
    'Máy chiếu', 
    'Vệ sinh phòng', 
    'Bàn ghế', 
    'Cây cối' // Mới thêm
  ];
  
  // Danh sách các khu vực
  const areas = [
    'Phòng 1', 'Phòng 2', 'Phòng 3', 'Phòng 4', 'Phòng 5', 
    'Phòng Lab', 'Phòng AM', 'Sảnh OA', 
    'CC Tầng G', 'CC Tầng 1', 
    'Thư Viện', 'Kho Tầng 3', 'Canteen'
  ];

  // State lưu trạng thái từng món: { 'Máy lạnh': 'Tốt', ... }
  const [statusMap, setStatusMap] = useState({});

  const handleStatusChange = (item, status) => {
    setStatusMap(prev => ({ ...prev, [item]: status }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    // Validate: Bắt buộc chọn khu vực
    if (!selectedArea) {
      alert("Vui lòng chọn khu vực kiểm tra!");
      return;
    }

    // Kiểm tra xem đã đánh giá hết các mục chưa
    const missingItems = items.filter(item => !statusMap[item]);
    if (missingItems.length > 0) {
      alert(`Bạn chưa kiểm tra: ${missingItems.join(', ')}`);
      return;
    }

    // Gửi log cho từng món kèm theo thông tin Khu vực (Area)
    items.forEach(item => {
      addFacilityLog({
        staffName: user.name,
        type: checkType,
        area: selectedArea, // Lưu thêm khu vực
        item: item,
        status: statusMap[item],
        time: new Date()
      });
    });

    alert(`Đã gửi báo cáo kiểm tra ${checkType} tại khu vực ${selectedArea}!`);
    
    // Reset form (giữ lại thời điểm và khu vực để check tiếp nếu cần, hoặc reset tùy logic)
    setStatusMap({});
    // setSelectedArea(''); // Bỏ comment dòng này nếu muốn reset khu vực sau khi gửi
  };

  return (
    <div>
      <h2 style={{ color: '#003366' }}>Kiểm tra Cơ sở vật chất & Cây xanh</h2>
      
      <div style={{ background: '#f9f9f9', padding: '15px', borderRadius: '8px', marginBottom: '20px', border: '1px solid #ddd' }}>
        {/* Chọn Thời điểm */}
        <div style={{ marginBottom: '15px' }}>
          <label style={{ display: 'inline-block', width: '100px', fontWeight: 'bold' }}>Thời điểm:</label>
          <select 
            value={checkType} 
            onChange={e => setCheckType(e.target.value)}
            style={{ padding: '5px 10px', borderRadius: '4px', border: '1px solid #ccc' }}
          >
            <option value="Đầu giờ">☀️ Đầu giờ (Start Shift)</option>
            <option value="Cuối giờ">🌙 Cuối giờ (End Shift)</option>
          </select>
        </div>

        {/* Chọn Khu vực */}
        <div>
          <label style={{ display: 'inline-block', width: '100px', fontWeight: 'bold' }}>Khu vực:</label>
          <select 
            value={selectedArea} 
            onChange={e => setSelectedArea(e.target.value)}
            required
            style={{ padding: '5px 10px', borderRadius: '4px', border: '1px solid #ccc', minWidth: '200px' }}
          >
            <option value="">-- Chọn phòng / khu vực --</option>
            {areas.map(area => (
              <option key={area} value={area}>{area}</option>
            ))}
          </select>
        </div>
      </div>

      <form onSubmit={handleSubmit}>
        <table border="1" cellPadding="10" style={{ borderCollapse: 'collapse', width: '100%', marginBottom: '20px', background: 'white', boxShadow: '0 2px 5px rgba(0,0,0,0.05)' }}>
          <thead>
            <tr style={{ background: '#eee', textAlign: 'left' }}>
              <th style={{ width: '40%' }}>Hạng mục kiểm tra</th>
              <th>Tình trạng hoạt động</th>
            </tr>
          </thead>
          <tbody>
            {items.map(item => (
              <tr key={item}>
                <td style={{ fontWeight: '500' }}>{item}</td>
                <td>
                  <div style={{ display: 'flex', gap: '20px' }}>
                    <label style={{ cursor: 'pointer', color: 'green' }}>
                      <input 
                        type="radio" 
                        name={item} 
                        value="Tốt" 
                        checked={statusMap[item] === 'Tốt'}
                        onChange={() => handleStatusChange(item, 'Tốt')} 
                        style={{ marginRight: '5px' }}
                      /> 
                      <strong>Tốt / Xanh tốt</strong>
                    </label>
                    <label style={{ cursor: 'pointer', color: 'red' }}>
                      <input 
                        type="radio" 
                        name={item} 
                        value="Hỏng" 
                        checked={statusMap[item] === 'Hỏng'}
                        onChange={() => handleStatusChange(item, 'Hỏng')} 
                        style={{ marginRight: '5px' }}
                      /> 
                      <strong>Hỏng / Héo úa / Bẩn</strong>
                    </label>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>

        <button 
          type="submit"
          style={{ 
            background: '#003366', 
            color: 'white', 
            border: 'none', 
            padding: '12px 30px', 
            borderRadius: '5px', 
            fontSize: '1rem', 
            fontWeight: 'bold', 
            cursor: 'pointer',
            boxShadow: '0 3px 6px rgba(0,0,0,0.2)'
          }}
        >
          GỬI BÁO CÁO
        </button>
      </form>
    </div>
  );
};

export default FacilityCheck;
